  ('aboriginal-d0d1b9a2-moex-00113', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-519af93a', 'sub-aboriginal-d0d1b9a2-03', NULL, 'single_choice', '某機關主管長官命令以不實之支出憑證核銷經費時，該機關主辦會計人員應如何處理？', '["聽從長官之指示", "口頭表示異議", "書面表示異議", "直接報告上級機關長官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "b320891c5923", "answer_pdf_sha1": "bef9620a3afb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00001', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-114-856e6567', 'sub-aboriginal-e0adf6cd-01', NULL, 'essay', '試從「經驗」與「民主」兩個角度闡釋美國教育哲學家杜威（J.Dewey）
「教育即生活」之內涵，並說明該主張對於我國《十二年國民基本教育
課程綱要總綱》核心素養導向之課程設計與教學方式之創新所呈顯的意
義。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:28+00:00", "source_pdf_sha1": "a84cee41d802", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "506", "s": "1003", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00002', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-114-856e6567', 'sub-aboriginal-e0adf6cd-01', NULL, 'essay', '弗洛姆（E.Fromm）係法蘭克福學派（Frankfurtschool）的重要成員，其
批判聚焦在現代人的生命處境之省察，著有《逃避自由》（Escape from
freedom），書中提及現代人往往在自由之前退卻，放棄了選擇的權利。
首先，試根據弗洛姆的觀察，說明現代人逃避自由的原因及逃避自由之
後衍生的生命課題；其次，論述學校教師宜如何規劃相關的教育活動，
以培養學生成為自主行動的生命主體。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:28+00:00", "source_pdf_sha1": "a84cee41d802", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "506", "s": "1003", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00003', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-114-856e6567', 'sub-aboriginal-e0adf6cd-01', NULL, 'essay', '道德哲學關心行為準則的建立，行為的評價為其核心要務。請舉例說明義
務（obligatory）道德行為與超義務（supererogatory）道德行為之涵義，並
說明培養這兩種道德行為之教育時，教育者宜採取的教導方式。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:28+00:00", "source_pdf_sha1": "a84cee41d802", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "506", "s": "1003", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL),
  ('aboriginal-e0adf6cd-moex-00004', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-114-856e6567', 'sub-aboriginal-e0adf6cd-01', NULL, 'essay', '我國教育部致力推動美感教育中長程計畫多時，呈顯出美育在高科技
時代的重要性。美感教育關注提升學生審美能力和美感創造力，必然
涉及美感判斷的客觀性問題。艾德勒（M.Adler）認為美感判斷有主觀
性的「令人愉悅之美（theenjoyablebeauty）」和客觀性的「令人讚賞之
美（theadmirablebeauty）」，試分別舉例說明其涵義並論述美感教育教
學時宜採取的做法。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:28+00:00", "source_pdf_sha1": "a84cee41d802", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "506", "s": "1003", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "教育行政"}'::jsonb, NULL)
